import { cva } from 'class-variance-authority'

export const scratchCardVariants = cva(
    [
        'relative',
        'border-3 border-brutal',
        'rounded-brutal',
        'overflow-hidden',
        'bg-brutal-bg',
    ]
)

import { ref, onMounted, onUnmounted, type Ref } from 'vue'
import { isClient } from '@/lib/env'

export function useReducedMotion(): Ref<boolean> {
    const prefersReduced = ref(false)
    let mediaQuery: MediaQueryList | null = null

    const onChange = (e: MediaQueryListEvent) => {
        prefersReduced.value = e.matches
    }

    onMounted(() => {
        if (isClient) {
            mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)')
            prefersReduced.value = mediaQuery.matches
            mediaQuery.addEventListener('change', onChange)
        }
    })

    onUnmounted(() => {
        mediaQuery?.removeEventListener('change', onChange)
    })

    return prefersReduced
}

import { ref, onMounted, onUnmounted, type Ref } from 'vue'
import { CANVAS_SAMPLE_GRID_SIZE, CANVAS_PROGRESS_CHECK_INTERVAL_MS, CANVAS_PROGRESS_THROTTLE_MS } from '@/lib/defaults'
import { createCanvasElement, getCanvas2DContext, getDevicePixelRatio, getResizeObserverCtor } from '@/lib/env'

const REVEAL_COMPLETED_FALLBACK_DURATION = 0

interface UseCanvasInteractionOptions {
    containerRef: Ref<HTMLDivElement | null>
    canvasRef: Ref<HTMLCanvasElement | null>
    brushRadius: Ref<number>
    percentage: Ref<number>
    fadeDuration: Ref<number>
    prefersReducedMotion: Ref<boolean>
    onProgress: (percent: number) => void
    onCompleted: () => void
    drawOverlay: (ctx: CanvasRenderingContext2D, width: number, height: number) => void
}

export interface UseCanvasInteractionReturn {
    ctx: Ref<CanvasRenderingContext2D | null>
    isRevealed: Ref<boolean>
    revealAll: () => void
    syncCanvasSize: () => void
    handlePointerDown: (e: PointerEvent) => void
    handlePointerMove: (e: PointerEvent) => void
    handlePointerUp: (e: PointerEvent) => void
    touchAction: 'none'
}

export function useCanvasInteraction(options: UseCanvasInteractionOptions): UseCanvasInteractionReturn {
    const {
        containerRef,
        canvasRef,
        brushRadius,
        percentage,
        fadeDuration,
        prefersReducedMotion,
        onProgress,
        onCompleted,
        drawOverlay,
    } = options

    const ctx = ref<CanvasRenderingContext2D | null>(null)
    const isRevealed = ref(false)

    let isScratching = false
    let resizeObserver: ResizeObserver | null = null
    let drawFrameCount = 0
    let lastProgressTime = 0
    let revealTimerId: ReturnType<typeof setTimeout> | null = null

    const syncCanvasSize = () => {
        const container = containerRef.value
        const canvas = canvasRef.value
        if (!container || !canvas) return

        // 保存当前 canvas 内容到临时 canvas，防止 resize 清除已刮除区域
        // 注意：新建 canvas 的默认尺寸是 300x150（非 0），但内容为空。
        // 必须通过 style.width/height 是否被显式设置来判断是否已初始化过，
        // 否则首次调用会误把空内容当作"旧内容"保存，导致 drawOverlay 永远不被调用。
        let tempCanvas: HTMLCanvasElement | null = null
        let hasOldContent = false
        let oldDpr = getDevicePixelRatio()
        const hasBeenSized = canvas.style.width !== '' && canvas.style.height !== ''
        if (hasBeenSized) {
            const oldCtx = getCanvas2DContext(canvas)
            const parsedStyleWidth = parseFloat(canvas.style.width)
            oldDpr = (oldCtx && canvas.width > 0 && Number.isFinite(parsedStyleWidth) && parsedStyleWidth > 0)
                ? canvas.width / parsedStyleWidth
                : getDevicePixelRatio()
            if (oldCtx && canvas.width > 0 && canvas.height > 0) {
                try {
                    tempCanvas = createCanvasElement()
                    if (!tempCanvas) {
                        throw new Error('Canvas is unavailable')
                    }
                    tempCanvas.width = canvas.width
                    tempCanvas.height = canvas.height
                    const tempCtx = getCanvas2DContext(tempCanvas)
                    if (tempCtx && typeof tempCtx.drawImage === 'function') {
                        tempCtx.drawImage(canvas, 0, 0)
                        hasOldContent = true
                    } else {
                        tempCanvas = null
                    }
                } catch {
                    tempCanvas = null
                }
            }
        }

        const rect = container.getBoundingClientRect()
        const dpr = getDevicePixelRatio()

        canvas.width = rect.width * dpr
        canvas.height = rect.height * dpr
        canvas.style.width = `${rect.width}px`
        canvas.style.height = `${rect.height}px`

        ctx.value = getCanvas2DContext(canvas)
        if (ctx.value) {
            ctx.value.scale(dpr, dpr)
            const w = canvas.width / dpr
            const h = canvas.height / dpr

            if (hasOldContent && tempCanvas) {
                // 恢复之前保存的内容，保留用户已刮除的进度
                ctx.value.drawImage(tempCanvas, 0, 0, tempCanvas.width / oldDpr, tempCanvas.height / oldDpr, 0, 0, w, h)
            } else {
                // 首次初始化，绘制覆盖层
                drawOverlay(ctx.value, w, h)
            }
        }
    }

    const calculateProgress = () => {
        const canvas = canvasRef.value
        const ctxVal = ctx.value
        if (!canvas || !ctxVal) return 0

        const w = canvas.width
        const h = canvas.height
        if (w === 0 || h === 0) return 0

        const imageData = ctxVal.getImageData(0, 0, w, h)
        const pixels = imageData.data

        let totalSampled = 0
        let cleared = 0

        for (let y = 0; y < h; y += CANVAS_SAMPLE_GRID_SIZE) {
            for (let x = 0; x < w; x += CANVAS_SAMPLE_GRID_SIZE) {
                const idx = (y * w + x) * 4 + 3
                totalSampled++
                if (pixels[idx] === 0) {
                    cleared++
                }
            }
        }

        if (totalSampled === 0) return 0
        return Math.round((cleared / totalSampled) * 100)
    }

    const checkProgress = () => {
        const percent = calculateProgress()
        onProgress(percent)

        if (percent >= percentage.value) {
            revealAll()
        }
    }

    const scratch = (clientX: number, clientY: number) => {
        const canvas = canvasRef.value
        const ctxVal = ctx.value
        if (!canvas || !ctxVal || isRevealed.value) return

        const rect = canvas.getBoundingClientRect()
        const x = clientX - rect.left
        const y = clientY - rect.top

        ctxVal.save()
        ctxVal.globalCompositeOperation = 'destination-out'
        ctxVal.beginPath()
        ctxVal.arc(x, y, brushRadius.value, 0, Math.PI * 2)
        ctxVal.fill()
        ctxVal.restore()

        drawFrameCount++
        if (drawFrameCount % CANVAS_PROGRESS_CHECK_INTERVAL_MS === 0) {
            const now = Date.now()
            if (now - lastProgressTime > CANVAS_PROGRESS_THROTTLE_MS) {
                checkProgress()
                lastProgressTime = now
            }
        }
    }

    const revealAll = () => {
        if (isRevealed.value) return
        isRevealed.value = true

        const duration = prefersReducedMotion.value ? REVEAL_COMPLETED_FALLBACK_DURATION : fadeDuration.value
        revealTimerId = setTimeout(() => {
            onCompleted()
            revealTimerId = null
        }, duration)
    }

    const handlePointerDown = (e: PointerEvent) => {
        if (!(e.target instanceof Element)) return
        isScratching = true
        try {
            e.target.setPointerCapture(e.pointerId)
        } catch {
            isScratching = false
            return
        }
        scratch(e.clientX, e.clientY)
    }

    const handlePointerMove = (e: PointerEvent) => {
        if (!isScratching) return
        scratch(e.clientX, e.clientY)
    }

    const handlePointerUp = (e: PointerEvent) => {
        if (isScratching) {
            if (e.target instanceof Element) {
                try {
                    e.target.releasePointerCapture(e.pointerId)
                } catch {
                    // Pointer may not be captured
                }
            }
            isScratching = false
            checkProgress()
        }
    }

    onMounted(() => {
        syncCanvasSize()
        if (containerRef.value) {
            const ResizeObserverCtor = getResizeObserverCtor()
            if (!ResizeObserverCtor) return
            resizeObserver = new ResizeObserverCtor(syncCanvasSize)
            resizeObserver.observe(containerRef.value)
        }
    })

    onUnmounted(() => {
        if (resizeObserver) {
            resizeObserver.disconnect()
        }
        if (revealTimerId) {
            clearTimeout(revealTimerId)
            revealTimerId = null
        }
    })

    return {
        ctx,
        isRevealed,
        revealAll,
        syncCanvasSize,
        handlePointerDown,
        handlePointerMove,
        handlePointerUp,
        touchAction: 'none' as const,
    }
}

import { type ComputedRef, type InjectionKey, type MaybeRef, computed, inject, provide, unref } from 'vue'
import { zhCN } from '@/locales/zh-CN'
import type { Locale } from '@/locales/types'

export const LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Locale>> = Symbol('brutx-ui-locale')
export const FALLBACK_LOCALE_INJECTION_KEY: InjectionKey<MaybeRef<Partial<Locale>>> = Symbol('brutx-ui-fallback-locale')

export type TranslateFunction = (path: string, params?: Record<string, string | number>) => string

export interface LocaleOptions {
    locale: MaybeRef<Locale>
    fallbackLocale?: MaybeRef<Partial<Locale>>
}

export function provideLocale(localeOrOptions: MaybeRef<Locale> | LocaleOptions): void {
    // 检查是否是 LocaleOptions 格式（包含 locale 属性）
    if (
        typeof localeOrOptions === 'object' &&
        localeOrOptions !== null &&
        'locale' in localeOrOptions
    ) {
        const options = localeOrOptions as LocaleOptions
        provide(LOCALE_INJECTION_KEY, options.locale)
        if (options.fallbackLocale) {
            provide(FALLBACK_LOCALE_INJECTION_KEY, options.fallbackLocale)
        }
    } else {
        // 直接传入 MaybeRef<Locale> 格式（向后兼容）
        provide(LOCALE_INJECTION_KEY, localeOrOptions as MaybeRef<Locale>)
    }
}

function resolveByPath(obj: unknown, path: string): string | undefined {
    const keys = path.split('.')
    let result: unknown = obj
    for (const key of keys) {
        if (typeof result !== 'object' || result === null) return undefined
        result = (result as Record<string, unknown>)[key]
    }
    return typeof result === 'string' ? result : undefined
}

function interpolate(template: string, params?: Record<string, string | number>): string {
    if (!params) return template
    return Object.entries(params).reduce(
        (str, [k, v]) => str.split(`{${k}}`).join(String(v)),
        template,
    )
}

export function useLocale(): { locale: ComputedRef<Locale>; t: TranslateFunction } {
    const injected = inject<MaybeRef<Locale> | undefined>(LOCALE_INJECTION_KEY, undefined)
    const injectedFallback = inject<MaybeRef<Partial<Locale>> | undefined>(FALLBACK_LOCALE_INJECTION_KEY, undefined)

    const locale = computed<Locale>(() => {
        const resolved = injected ? unref(injected) : undefined
        return resolved ?? zhCN
    })

    const fallbackLocale = computed<Partial<Locale>>(() => {
        return injectedFallback ? unref(injectedFallback) : {}
    })

    function t(path: string, params?: Record<string, string | number>): string {
        // 1. 尝试从用户 locale 查找
        const currentVal = resolveByPath(locale.value, path)
        if (currentVal !== undefined) return interpolate(currentVal, params)

        // 2. 尝试从自定义 fallback locale 查找
        if (fallbackLocale.value && Object.keys(fallbackLocale.value).length > 0) {
            const fallbackVal = resolveByPath(fallbackLocale.value, path)
            if (fallbackVal !== undefined) return interpolate(fallbackVal, params)
        }

        // 3. 尝试从默认 zhCN 查找
        const zhCNVal = resolveByPath(zhCN, path)
        if (zhCNVal !== undefined) return interpolate(zhCNVal, params)

        // 4. 返回 path 原文
        return path
    }

    return { locale, t }
}

/**
 * Environment detection utilities for SSR compatibility.
 * Use these instead of scattered `typeof document/window` checks.
 */

/** Whether the code is running in a browser environment (not SSR). */
export const isClient = typeof window !== 'undefined'

/** Whether `document` is available. */
export const hasDocument = typeof document !== 'undefined'

/** Whether `localStorage` is available (may be blocked in Safari private mode). */
export const hasLocalStorage = typeof localStorage !== 'undefined'

/** Whether `document.body` is available for imperative mounting. */
export function canUseDocumentBody(): boolean {
    return hasDocument && document.body !== null
}

/** Whether IntersectionObserver is available. */
export const hasIntersectionObserver = isClient && typeof window.IntersectionObserver !== 'undefined'

type AudioContextConstructor = typeof AudioContext
type ResizeObserverConstructor = typeof ResizeObserver
type MutationObserverConstructor = typeof MutationObserver

export interface ViewportSize {
    width: number
    height: number
}

/** Get the available AudioContext constructor, including Safari's prefixed API. */
export function getAudioContextCtor(): AudioContextConstructor | null {
    if (!isClient) return null
    return window.AudioContext
        ?? (window as Window & typeof globalThis & { webkitAudioContext?: AudioContextConstructor }).webkitAudioContext
        ?? null
}

/** Get the available ResizeObserver constructor. */
export function getResizeObserverCtor(): ResizeObserverConstructor | null {
    if (!isClient) return null
    return window.ResizeObserver ?? null
}

/** Get the available MutationObserver constructor. */
export function getMutationObserverCtor(): MutationObserverConstructor | null {
    if (!isClient) return null
    return window.MutationObserver ?? null
}

/** Get the current device pixel ratio with an SSR-safe fallback. */
export function getDevicePixelRatio(): number {
    if (!isClient) return 1
    return window.devicePixelRatio || 1
}

/** Get viewport dimensions with an SSR-safe fallback. */
export function getViewportSize(): ViewportSize {
    if (!isClient) return { width: 0, height: 0 }
    return {
        width: window.innerWidth,
        height: window.innerHeight,
    }
}

/** Create a canvas element when the DOM supports it. */
export function createCanvasElement(): HTMLCanvasElement | null {
    if (!hasDocument) return null
    try {
        return document.createElement('canvas')
    } catch {
        return null
    }
}

/** Get a 2D rendering context without leaking capability errors to callers. */
export function getCanvas2DContext(canvas: HTMLCanvasElement): CanvasRenderingContext2D | null {
    try {
        return canvas.getContext('2d')
    } catch {
        return null
    }
}

/**
 * Safely get a value from localStorage.
 * Returns `null` if localStorage is unavailable or the key doesn't exist.
 */
export function safeGetStorageItem(key: string): string | null {
    try {
        if (!hasLocalStorage) return null
        return localStorage.getItem(key)
    } catch {
        return null
    }
}

/**
 * Safely set a value in localStorage.
 * Silently fails if localStorage is unavailable (e.g. Safari private mode, storage full).
 */
export function safeSetStorageItem(key: string, value: string): void {
    try {
        if (!hasLocalStorage) return
        localStorage.setItem(key, value)
    } catch {
        // Storage full or blocked (e.g. Safari private mode)
    }
}

